import  React, { Component } from 'react';

export class Blog extends Component {
    render() {
        return  <div class='post'>
        <p> {this.props.children} </p>
        <p style={{
            float: 'right',
            fontSize: '50%'
        }}> {this.props.date} </p>
        {this.props.image &&  <img src={`${process.env.PUBLIC_URL}/images/${this.props.image}`} alt='not found' />}
    </div>
    }
}